#include<bits/stdc++.h>
using namespace std;
int n;
long long mod;
struct matrix
{
    __int128 a[110][110];
    matrix()
    {
        for(int i=1;i<=3;i++)
        {
            for(int j=1;j<=3;j++)
            {
                a[i][j]=0;
            }
        }
    }
    __int128* operator[](const int x)const
    {
        return (__int128*)a[x];
    }
    matrix operator*(const matrix&b)const
    {
        matrix c;
        for(int i=1;i<=3;i++)
        {
            for(int j=1;j<=3;j++)
            {
                for(int k=1;k<=3;k++)
                {
                    c[i][j]+=a[i][k]*b[k][j]%mod;
                    c[i][j]%=mod;
                }
            }
        }
        return c;
    }
}ans,base,ans1;
void fastpow(long long k)
{
    while(k)
    {
        if(k%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        k/=2;
    }
}
int main()
{
    long long a,c,x0,n,g;
    scanf("%lld%lld%lld%lld%lld%lld",&mod,&a,&c,&x0,&n,&g);
    ans1[1][1]=x0;
    ans1[2][1]=c;
    ans[1][1]=a;
    ans[1][2]=ans[2][2]=1;
    base=ans;
    fastpow(n-1);
    ans=ans*ans1;
    printf("%lld",(long long)(ans[1][1]%g));
    return 0;
}
